.t-input {
  display: inline-flex;
  align-items: center;
  width: 100%;
  padding: 0 12px;
  border: 1px solid #dcdcdc;
  border-radius: 6px;
  background: #fff;
  box-sizing: border-box;
  transition: border-color 0.2s;
  gap: 8px;

  &--small  { height: 32px; font-size: 13px; }
  &--medium { height: 40px; font-size: 14px; }
  &--large  { height: 48px; font-size: 16px; }

  &--status-success { border-color: #2ba471; }
  &--status-warning { border-color: #ed7b2f; }
  &--status-error   { border-color: #d54941; }

  &--disabled { background: #f3f3f3; cursor: not-allowed; }
  &--readonly { background: #fafafa; }

  &__inner {
    flex: 1;
    min-width: 0;
    border: none;
    outline: none;
    background: transparent;
    color: #181818;
    font: inherit;
  }

  &__prefix,
  &__suffix { display: inline-flex; align-items: center; color: #888; }

  &__clear {
    width: 16px;
    height: 16px;
    line-height: 16px;
    text-align: center;
    border-radius: 50%;
    background: #c5c5c5;
    color: #fff;
    font-size: 12px;
    cursor: pointer;
  }
}

/**
 * Input 组件类型契约
 */

export type InputType = 'text' | 'number' | 'password' | 'tel' | 'email' | 'search';

export type InputSize = 'small' | 'medium' | 'large';

export type InputStatus = 'default' | 'success' | 'warning' | 'error';

export interface InputProps {
  /** v-model 值 */
  modelValue?: string;
  /** 占位文本 */
  placeholder?: string;
  /** 输入类型 */
  type?: InputType;
  /** 尺寸 */
  size?: InputSize;
  /** 校验状态 */
  status?: InputStatus;
  /** 是否禁用 */
  disabled?: boolean;
  /** 是否只读 */
  readonly?: boolean;
  /** 是否显示清除按钮 */
  clearable?: boolean;
  /** 最大长度（<=0 不限制） */
  maxlength?: number;
  /** 透传额外类名 */
  customClass?: string;
}

export interface InputEmits {
  (e: 'update:modelValue', value: string): void;
  (e: 'change', value: string): void;
  (e: 'focus', event: FocusEvent): void;
  (e: 'blur', event: FocusEvent): void;
  (e: 'clear'): void;
  (e: 'enter', value: string): void;
}

import { cva } from '../../utils/cva';

export const inputVariants = cva('t-input', {
  variants: {
    size: {
      small: 't-input--small',
      medium: 't-input--medium',
      large: 't-input--large',
    },
    status: {
      default: 't-input--status-default',
      success: 't-input--status-success',
      warning: 't-input--status-warning',
      error: 't-input--status-error',
    },
    disabled: { true: 't-input--disabled' },
    readonly: { true: 't-input--readonly' },
  },
  defaultVariants: {
    size: 'medium',
    status: 'default',
  },
});
